// Package goldilocks provides elliptic curve operations over the goldilocks curve.package goldilocksimport fp "github.com/cloudflare/circl/math/fp448"// Curve is the Goldilocks curve x^2+y^2=z^2-39081x^2y^2.type Curve struct{}// Identity returns the identity point.rve) Identity() *Point {return &Point{y: fp.One(),z: fp.One(),}}// IsOnCurve returns true if the point lies on the curve.rve) IsOnCurve(P *Point) bool {x2, y2, t, t2, z2 := &fp.Elt{}, &fp.Elt{}, &fp.Elt{}, &fp.Elt{}, &fp.Elt{}rhs, lhs := &fp.Elt{}, &fp.Elt{}fp.Mul(t, &P.ta, &P.tb)  // t = ta*tbfp.Sqr(x2, &P.x)// x^2fp.Sqr(y2, &P.y)// y^2fp.Sqr(z2, &P.z)// z^2fp.Sqr(t2, t)   // t^2fp.Add(lhs, x2, y2)      // x^2 + y^2fp.Mul(rhs, t2, &paramD) // dt^2fp.Add(rhs, rhs, z2)     // z^2 + dt^2fp.Sub(lhs, lhs, rhs)    // x^2 + y^2 - (z^2 + dt^2)eq0 := fp.IsZero(lhs)fp.Mul(lhs, &P.x, &P.y) // xyfp.Mul(rhs, t, &P.z)    // tzfp.Sub(lhs, lhs, rhs)   // xy - tzeq1 := fp.IsZero(lhs)return eq0 && eq1}// Generator returns the generator point.rve) Generator() *Point {return &Point{x:  genX,y:  genY,z:  fp.One(),ta: genX,tb: genY,}}// Order returns the number of points in the prime subgroup.rve) Order() Scalar { return order }// Double returns 2P.rve) Double(P *Point) *Point { R := *P; R.Double(); return &R }// Add returns P+Q.rve) Add(P, Q *Point) *Point { R := *P; R.Add(Q); return &R }// ScalarMult returns kP. This  runs in constant time.Curve) ScalarMult(k *Scalar, P *Point) *Point {k4 := &Scalar{}k4.divBy4(k)return e.pull(twistCurve{}.ScalarMult(k4, e.push(P)))}// ScalarBaseMult returns kG where G is the generator point. This  runs in constant time.Curve) ScalarBaseMult(k *Scalar) *Point {k4 := &Scalar{}k4.divBy4(k)return e.pull(twistCurve{}.ScalarBaseMult(k4))}// CombinedMult returns mG+nP, where G is the generator point. This  is non-constant time.Curve) CombinedMult(m, n *Scalar, P *Point) *Point {m4 := &Scalar{}n4 := &Scalar{}m4.divBy4(m)n4.divBy4(n)return e.pull(twistCurve{}.CombinedMult(m4, n4, twistCurve{}.pull(P)))}